```powershell
# Requires: PowerShell 5.1+ or PowerShell 7+
# Run as Administrator for best results

$ErrorActionPreference = 'Stop'

function Test-Administrator {
    $currentIdentity = [Security.Principal.WindowsIdentity]::GetCurrent()
    $principal = New-Object Security.Principal.WindowsPrincipal($currentIdentity)
    return $principal.IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)
}

function Get-SystemFileSample {
    $paths = @(
        "$env:windir\System32\ntoskrnl.exe",
        "$env:windir\System32\kernel32.dll",
        "$env:windir\System32\winload.exe",
        "$env:windir\explorer.exe"
    )
    $paths | Where-Object { Test-Path $_ }
}

Write-Host "=== System Integrity Verification ===" -ForegroundColor Cyan

if (-not (Test-Administrator)) {
    Write-Warning "Not running as Administrator. Some checks may be limited."
}

# Try to locate Get-VataSignature if it exists
$vataCmd = Get-Command -Name Get-VataSignature -ErrorAction SilentlyContinue

if ($vataCmd) {
    Write-Host "`n[1] Using Get-VataSignature..." -ForegroundColor Yellow

    $files = Get-SystemFileSample
    foreach ($file in $files) {
        try {
            $result = Get-VataSignature -Path $file
            [PSCustomObject]@{
                File   = $file
                Result = $result
            }
        }
        catch {
            Write-Warning "Get-VataSignature failed for $file : $_"
        }
    }
}
else {
    Write-Warning "Get-VataSignature was not found. Falling back to standard Windows integrity checks."

    Write-Host "`n[1] Authenticode signature checks..." -ForegroundColor Yellow
    $files = Get-SystemFileSample
    $sigResults = foreach ($file in $files) {
        $sig = Get-AuthenticodeSignature -FilePath $file
        [PSCustomObject]@{
            File         = $file
            Status       = $sig.Status
            StatusMessage= $sig.StatusMessage
            Signer       = $sig.SignerCertificate.Subject
        }
    }
    $sigResults | Format-Table -AutoSize

    Write-Host "`n[2] Running System File Checker verification..." -ForegroundColor Yellow
    cmd /c "sfc /verifyonly"

    Write-Host "`n[3] Running DISM component store scan..." -ForegroundColor Yellow
    DISM /Online /Cleanup-Image /ScanHealth
}

Write-Host "`nIntegrity verification completed." -ForegroundColor Green
```

